import secrets
import hashlib
import time
from datetime import datetime, timedelta
from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
import smtplib
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
import os

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = os.getenv('DATABASE_URL', 'sqlite:///users.db')
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
app.config['SECRET_KEY'] = os.getenv('SECRET_KEY', 'your-secret-key-change-in-production')

db = SQLAlchemy(app)

limiter = Limiter(
    app=app,
    key_func=get_remote_address,
    default_limits=["200 per day", "50 per hour"],
    storage_uri="memory://"
)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(255), nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

class PasswordResetToken(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    token_hash = db.Column(db.String(255), unique=True, nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)
    expires_at = db.Column(db.DateTime, nullable=False)
    used = db.Column(db.Boolean, default=False)
    
    user = db.relationship('User', backref=db.backref('reset_tokens', lazy=True))

with app.app_context():
    db.create_all()

def generate_token():
    return secrets.token_urlsafe(32)

def hash_token(token):
    return hashlib.sha256(token.encode()).hexdigest()

def send_reset_email(email, reset_link):
    smtp_server = os.getenv('SMTP_SERVER', 'smtp.gmail.com')
    smtp_port = int(os.getenv('SMTP_PORT', '587'))
    smtp_username = os.getenv('SMTP_USERNAME', '')
    smtp_password = os.getenv('SMTP_PASSWORD', '')
    from_email = os.getenv('FROM_EMAIL', smtp_username)
    
    if not smtp_username or not smtp_password:
        print(f"Email would be sent to {email} with link: {reset_link}")
        return True
    
    try:
        msg = MIMEMultipart('alternative')
        msg['Subject'] = 'Password Reset Request'
        msg['From'] = from_email
        msg['To'] = email
        
        text = f"""
        Hello,
        
        You requested a password reset. Click the link below to reset your password:
        
        {reset_link}
        
        This link will expire in 1 hour.
        
        If you didn't request this, please ignore this email.
        """
        
        html = f"""
        <html>
          <body>
            <p>Hello,</p>
            <p>You requested a password reset. Click the link below to reset your password:</p>
            <p><a href="{reset_link}">Reset Password</a></p>
            <p>This link will expire in 1 hour.</p>
            <p>If you didn't request this, please ignore this email.</p>
          </body>
        </html>
        """
        
        part1 = MIMEText(text, 'plain')
        part2 = MIMEText(html, 'html')
        
        msg.attach(part1)
        msg.attach(part2)
        
        with smtplib.SMTP(smtp_server, smtp_port) as server:
            server.starttls()
            server.login(smtp_username, smtp_password)
            server.send_message(msg)
        
        return True
    except Exception as e:
        print(f"Error sending email: {e}")
        return False

@app.route('/api/password-reset/request', methods=['POST'])
@limiter.limit("3 per hour")
def request_password_reset():
    start_time = time.time()
    
    data = request.get_json()
    
    if not data or 'email' not in data:
        time.sleep(max(0, 1.0 - (time.time() - start_time)))
        return jsonify({'message': 'If an account exists with this email, a reset link has been sent.'}), 200
    
    email = data['email'].strip().lower()
    
    if not email or '@' not in email:
        time.sleep(max(0, 1.0 - (time.time() - start_time)))
        return jsonify({'message': 'If an account exists with this email, a reset link has been sent.'}), 200
    
    user = User.query.filter_by(email=email).first()
    
    if user:
        PasswordResetToken.query.filter_by(user_id=user.id, used=False).filter(
            PasswordResetToken.expires_at > datetime.utcnow()
        ).update({'used': True})
        db.session.commit()
        
        token = generate_token()
        token_hash = hash_token(token)
        
        expires_at = datetime.utcnow() + timedelta(hours=1)
        
        reset_token = PasswordResetToken(
            user_id=user.id,
            token_hash=token_hash,
            expires_at=expires_at
        )
        
        db.session.add(reset_token)
        db.session.commit()
        
        base_url = os.getenv('BASE_URL', 'http://localhost:5000')
        reset_link = f"{base_url}/reset-password?token={token}"
        
        send_reset_email(email, reset_link)
    
    time.sleep(max(0, 1.0 - (time.time() - start_time)))
    
    return jsonify({'message': 'If an account exists with this email, a reset link has been sent.'}), 200

@app.route('/api/password-reset/verify', methods=['POST'])
@limiter.limit("10 per hour")
def verify_reset_token():
    data = request.get_json()
    
    if not data or 'token' not in data:
        return jsonify({'error': 'Invalid request'}), 400
    
    token = data['token']
    token_hash = hash_token(token)
    
    reset_token = PasswordResetToken.query.filter_by(
        token_hash=token_hash,
        used=False
    ).filter(
        PasswordResetToken.expires_at > datetime.utcnow()
    ).first()
    
    if not reset_token:
        return jsonify({'error': 'Invalid or expired token'}), 400
    
    return jsonify({'message': 'Token is valid', 'email': reset_token.user.email}), 200

@app.route('/api/password-reset/confirm', methods=['POST'])
@limiter.limit("5 per hour")
def confirm_password_reset():
    data = request.get_json()
    
    if not data or 'token' not in data or 'new_password' not in data:
        return jsonify({'error': 'Invalid request'}), 400
    
    token = data['token']
    new_password = data['new_password']
    
    if len(new_password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400
    
    token_hash = hash_token(token)
    
    reset_token = PasswordResetToken.query.filter_by(
        token_hash=token_hash,
        used=False
    ).filter(
        PasswordResetToken.expires_at > datetime.utcnow()
    ).first()
    
    if not reset_token:
        return jsonify({'error': 'Invalid or expired token'}), 400
    
    user = reset_token.user
    user.password_hash = hashlib.sha256(new_password.encode()).hexdigest()
    
    reset_token.used = True
    
    db.session.commit()
    
    return jsonify({'message': 'Password has been reset successfully'}), 200

@app.route('/api/user/register', methods=['POST'])
@limiter.limit("5 per hour")
def register_user():
    data = request.get_json()
    
    if not data or 'email' not in data or 'password' not in data:
        return jsonify({'error': 'Email and password required'}), 400
    
    email = data['email'].strip().lower()
    password = data['password']
    
    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400
    
    if User.query.filter_by(email=email).first():
        return jsonify({'error': 'Email already registered'}), 400
    
    password_hash = hashlib.sha256(password.encode()).hexdigest()
    
    user = User(email=email, password_hash=password_hash)
    db.session.add(user)
    db.session.commit()
    
    return jsonify({'message': 'User registered successfully', 'user_id': user.id}), 201

if __name__ == '__main__':
    app.run(debug=True)